"""# **4. Testing and selecting appropriate priors**

**Prior is a probability distribution that represents your beliefs about a parameter before observing any data.**

**Prior knowledge**

> Choose a prior distribution based on domain knowledge or previous studies.

> For numerical features: Often use Normal(μ=0, σ=1) or Student's t-distribution.

> For binary features: Uniform(-a, a) or Normal(μ=0, σ=1) are common.

> For strictly positive features: Gamma or Log-Normal distributions.

## 4.1 Choosing Prior For Binary Predictors

> **Using Kolmogorov-Smirnov (KS)  statistic to judge which prior distribution our predictor is more similar to.**

> The Kolmogorov-Smirnov (KS) statistic is a measure used in the Kolmogorov-Smirnov test to quantify the distance between probability distributions.

> A smaller KS statistic indicates that the two distributions are more similar.

> **Testing binary predictor for four different distributions as these are a potential choice for binary predictors- 'Bernoulli', 'Binomial', 'Poisson', 'Uniform'.**
"""

def test_and_fit_binary_distributions(binary_feature, col):
    ks_results = {}
    fitted_distributions = {}

    mean = binary_feature.mean()
    n = len(binary_feature)

    for dist_name in ['Bernoulli', 'Binomial', 'Poisson', 'Uniform']:
        try:
            if dist_name == "Bernoulli":
                params = (mean,)
                fitted_distributions[dist_name] = params
                ks_stat, p_value = kstest(binary_feature, 'bernoulli', args=params)

            elif dist_name == "Binomial":
                params = (1, mean)  # Use n=1 for binary data
                fitted_distributions[dist_name] = params
                ks_stat, p_value = kstest(binary_feature, 'binom', args=params)

            elif dist_name == "Poisson":
                lambda_param = mean
                params = (lambda_param,)
                fitted_distributions[dist_name] = params
                ks_stat, p_value = kstest(binary_feature, 'poisson', args=params)

            elif dist_name == "Uniform":
                params = (0, 1)  # Uniform distribution between 0 and 1
                fitted_distributions[dist_name] = params
                ks_stat, p_value = kstest(binary_feature, 'uniform', args=params)

            ks_results[dist_name] = {
                'KS Statistic': ks_stat,
            }

        except Exception as e:
            print(f"Error fitting {dist_name} for feature '{col}': {e}")
            ks_results[dist_name] = {'KS Statistic': np.inf}

    return ks_results, fitted_distributions

def visualize_binary_priors(binary_feature, col_name, ks_results, fitted_distributions):
    fig, axs = plt.subplots(1, 4, figsize=(20, 5))
    fig.suptitle(f"Prior Distributions for Binary Feature: {col_name}", fontsize=14)

    # Bernoulli plot
    x_bern = np.array([0, 1])
    p = fitted_distributions['Bernoulli'][0]
    y_bernoulli = bernoulli.pmf(x_bern, p)
    axs[0].bar(x_bern, y_bernoulli, color='blue', alpha=0.7)
    axs[0].set_title(f"Bernoulli (p={p:.2f})\n(KS={ks_results['Bernoulli']['KS Statistic']:.4f})")
    axs[0].set_xticks(x_bern)
    axs[0].set_ylabel('Probability')
    axs[0].set_ylim(0, 1)

    # Binomial plot
    x_binom = np.array([0, 1])  # Binary outcomes
    n_trials, prob = fitted_distributions['Binomial']
    y_binomial = binom.pmf(x_binom, n_trials, prob)
    axs[1].bar(x_binom, y_binomial, color='green', alpha=0.7)
    axs[1].set_title(f"Binomial (n={n_trials}, p={prob:.2f})\n(KS={ks_results['Binomial']['KS Statistic']:.4f})")
    axs[1].set_xlabel('Number of successes')
    axs[1].set_ylabel('Probability')
    axs[1].set_ylim(0, 1)
    axs[1].set_xticks(x_binom)

    # Poisson plot
    lambda_param = fitted_distributions['Poisson'][0]
    x_pois = np.arange(0, max(4, int(lambda_param * 3)))
    y_poisson = poisson.pmf(x_pois, lambda_param)
    axs[2].bar(x_pois, y_poisson, color='red', alpha=0.7)
    axs[2].set_title(f"Poisson (λ={lambda_param:.2f})\n(KS={ks_results['Poisson']['KS Statistic']:.4f})")
    axs[2].set_xticks(x_pois)
    axs[2].set_ylabel('Probability')
    axs[2].set_ylim(0, max(y_poisson) * 1.1)

    # Uniform plot
    x_unif = np.array([0, 1])
    y_uniform = uniform.pdf(x_unif, *fitted_distributions['Uniform'])
    axs[3].bar(x_unif, y_uniform, color='purple', alpha=0.7)
    axs[3].set_title(f"Uniform (a=0, b=1)\n(KS={ks_results['Uniform']['KS Statistic']:.4f})")
    axs[3].set_xticks(x_unif)
    axs[3].set_ylabel('Probability')
    axs[3].set_ylim(0, max(y_uniform) * 1.1)

    plt.tight_layout(rect=[0, 0.03, 1, 0.95])
    plt.show()

    print(f"\nResults for Binary Feature: {col_name}")
    for dist_name, stats in ks_results.items():
        print(f"{dist_name}: KS Statistic = {stats['KS Statistic']:.4f}")

    # Find the minimum KS statistic
    min_ks = min(stats['KS Statistic'] for stats in ks_results.values())

    # Find all distributions with the minimum KS statistic
    best_fits = [dist for dist, stats in ks_results.items() if stats['KS Statistic'] == min_ks]

    # Choose uniform if it's among the best fits, otherwise choose the first best fit
    if 'Uniform' in best_fits:
        best_fit = 'Uniform'
    else:
        best_fit = best_fits[0]

    print(f"Best Fit: {best_fit} (KS Statistic = {ks_results[best_fit]['KS Statistic']:.4f})")
    print("-" * 50)

    return best_fit  # Return the name of the best fitting distribution

def select_best_priors(df, binary_cols):
    best_priors = {}
    for col in binary_cols:
        binary_feature = df[col].dropna()
