# List of distributions to test
distributions = {
    'Normal': norm,
    'Uniform': uniform,
    'Exponential': expon,
    'Log-Normal': lognorm,
    'Gamma': gamma
}

# Function to test and fit distributions
def test_and_fit_distributions(feature, col):
    ks_results = {}
    fitted_distributions = {}

    scaled_feature = (feature - feature.min()) / (feature.max() - feature.min())

    for dist_name, dist in distributions.items():
        try:
            # Use scaled feature for Uniform
            data_to_fit = scaled_feature if dist_name == "Uniform" else feature

            if dist_name == "Normal":
                mean, std = feature.mean(), feature.std()
                params = (mean, std)

            elif dist_name == "Exponential":
                rate = 1 / feature.mean()
                params = (0, rate)

            elif dist_name == "Log-Normal":
                shape, loc, scale = dist.fit(data_to_fit)
                params = (shape, loc, scale)

            else:
                params = dist.fit(data_to_fit)

            fitted_distributions[dist_name] = params

            if dist_name == "Uniform":
                ks_stat, p_value = kstest(data_to_fit, "uniform")
            elif dist_name == "Normal":
                ks_stat, p_value = kstest(data_to_fit, "norm", args=params)
            elif dist_name == "Exponential":
                ks_stat, p_value = kstest(data_to_fit, "expon", args=params)
            elif dist_name == "Log-Normal":
                ks_stat, p_value = kstest(data_to_fit, "lognorm", args=params)
            elif dist_name == "Gamma":
                ks_stat, p_value = kstest(data_to_fit, "gamma", args=params)

            ks_results[dist_name] = {'KS Statistic': ks_stat, 'p-value': p_value}

        except Exception as e:
            ks_results[dist_name] = {'KS Statistic': np.inf, 'p-value': 0}
            print(f"Error fitting {dist_name} for feature '{col}': {e}")

    return ks_results, fitted_distributions

# Function to visualize individual priors
def visualize_individual_priors(feature, col_name, ks_results, fitted_distributions):
    fig, axs = plt.subplots(1, 5, figsize=(25, 5))
    fig.suptitle(f"Prior Distributions for Feature: {col_name}", fontsize=16)

    x = np.linspace(feature.min(), feature.max(), 100)

    for i, (dist_name, params) in enumerate(fitted_distributions.items()):
        try:
            dist = distributions[dist_name]
            if dist_name == "Uniform":
                y = dist.pdf(x, loc=0, scale=1)
            elif dist_name == "Log-Normal":
                y = dist.pdf(x, s=params[0], loc=params[1], scale=params[2])
            else:
                y = dist.pdf(x, *params)

            axs[i].hist(feature, bins=30, density=True, alpha=0.5, label='Data', color='gray', edgecolor='black')
            axs[i].plot(x, y, label=f'{dist_name} PDF', color='red')
            axs[i].set_title(f"{dist_name}\n(KS={ks_results[dist_name]['KS Statistic']:.4f}, p={ks_results[dist_name]['p-value']:.4e})")
            axs[i].legend()
        except Exception as e:
            axs[i].set_title(f"{dist_name} Fit Failed\n{str(e)}")

    plt.tight_layout(rect=[0, 0.03, 1, 0.95])
    plt.show()

    # Print results and the best fit
    print(f"\nResults for Feature: {col_name}")
    for dist_name, stats in ks_results.items():
        print(f"{dist_name}: KS Statistic = {stats['KS Statistic']:.4f}, p-value = {stats['p-value']:.4e}")

    best_fit = min(ks_results.items(), key=lambda x: x[1]['KS Statistic'])
    print(f"Best Fit: {best_fit[0]} (KS Statistic = {best_fit[1]['KS Statistic']:.4f}, p-value = {best_fit[1]['p-value']:.4e})")
    print("-" * 50)

def find_best_fits(df):
    best_fits = {}

    for col in df.columns:
        feature = df[col].dropna()
        if feature.nunique() > 2:
            ks_results, fitted_distributions = test_and_fit_distributions(feature, col)
            visualize_individual_priors(feature, col, ks_results, fitted_distributions)

            best_fit_dist = min(ks_results.items(), key=lambda x: x[1]['KS Statistic'])[0]
            best_fits[col] = best_fit_dist

    return best_fits

