"""> **Sampler used: NUTS (No u-turn sampler)**

> its a variant of Hamiltonian Monte Carlo (HMC)

> Automatically tunes its own hyperparameters during warmup to provide efficient sampling.

Likelihood function used here:

![image.png](data:image/png;base64,)
"""

## Uses No-U-Turn Sampler (NUTS).
## NUTS is an adaptive variant of Hamiltonian Monte Carlo (HMC) that automatically tunes its own hyperparameters during warmup to provide efficient sampling.
with pm.Model() as manual_logistic_model:
    # Intercept
    intercept = pm.Normal('intercept', mu=0, sigma=1)

    # Coefficients for numerical features
    beta_tenure = pm.Normal('beta_tenure', mu=0, sigma=1)
    beta_monthly_charges = pm.Normal('beta_monthly_charges', mu=0, sigma=1)
    beta_total_charges = pm.Gamma('beta_total_charges', alpha=1, beta=1)

    # Coefficients for binary features
    beta_gender = pm.Uniform('beta_gender', lower=-a, upper=a)
    beta_senior_citizen = pm.Uniform('beta_senior_citizen', lower=-a, upper=a)
    beta_partner = pm.Uniform('beta_partner', lower=-a, upper=a)
    beta_dependents = pm.Uniform('beta_dependents', lower=-a, upper=a)
    beta_multiple_lines = pm.Uniform('beta_multiple_lines', lower=-a, upper=a)
    beta_online_security = pm.Uniform('beta_online_security', lower=-a, upper=a)
    beta_online_backup = pm.Uniform('beta_online_backup', lower=-a, upper=a)
    beta_device_protection = pm.Uniform('beta_device_protection', lower=-a, upper=a)
    beta_tech_support = pm.Uniform('beta_tech_support', lower=-a, upper=a)
    beta_streaming_tv = pm.Uniform('beta_streaming_tv', lower=-a, upper=a)
    beta_streaming_movies = pm.Uniform('beta_streaming_movies', lower=-a, upper=a)
    beta_is_dsl = pm.Uniform('beta_is_dsl', lower=-a, upper=a)
    beta_is_fiber_optic = pm.Uniform('beta_is_fiber_optic', lower=-a, upper=a)

    # Coefficients for previously Poisson features
    beta_phone_service = pm.Uniform('beta_phone_service', lower=-a, upper=a)
    beta_paperless_billing = pm.Uniform('beta_paperless_billing', lower=-a, upper=a)

    # Linear combination
    linear_combination = (
        intercept +
        beta_tenure * X_train.tenure +
        beta_monthly_charges * X_train.MonthlyCharges +
        beta_total_charges * X_train.TotalCharges +
        beta_gender * X_train.gender +
        beta_senior_citizen * X_train.SeniorCitizen +
        beta_partner * X_train.Partner +
        beta_dependents * X_train.Dependents +
        beta_phone_service * X_train.PhoneService +
        beta_multiple_lines * X_train.MultipleLines +
        beta_online_security * X_train.OnlineSecurity +
        beta_online_backup * X_train.OnlineBackup +
        beta_device_protection * X_train.DeviceProtection +
        beta_tech_support * X_train.TechSupport +
        beta_streaming_tv * X_train.StreamingTV +
        beta_streaming_movies * X_train.StreamingMovies +
        beta_paperless_billing * X_train.PaperlessBilling +
        beta_is_dsl * X_train.IS_DSL +
        beta_is_fiber_optic * X_train['IS_Fiber optic']
    )

    # Likelihood
    likelihood = pm.invlogit(linear_combination)
    y_obs = pm.Bernoulli('y_obs', p=likelihood, observed=y_train)

    # Sampling
    trace = pm.sample(tune=1000,
                      draws=1000,
                      chains=2,
                      init='adapt_diag',
                      cores=3)

"""### **5.2 Posterior summary**

**Distribution Measures:**

mean: The posterior mean (expected value) of each parameter

sd: The posterior standard deviation, showing uncertainty

hdi_3% and hdi_97%: The 94% Highest Density Interval bounds, showing the range
where 94% of the credible values lie

**Diagnostic Statistics:**

mcse_mean and mcse_sd: Monte Carlo Standard Error for mean and standard deviation

ess_bulk and ess_tail: Effective Sample Size for bulk and tail of the distributions

r_hat: Convergence diagnostic (all 1.0 indicating good convergence)
"""

az.summary(trace)

